-- Detailed knowledge content for chapters 6, 9, 11-14
-- Extracted from "Школа альпинизма" (Учебное пособие ФАР)
-- Content in Russian, focused on practical knowledge for beginner-intermediate mountaineers

-- ============================================================
-- Chapter 6: Лавины
-- ============================================================

UPDATE kg_nodes SET content = 'Лавина — это масса снега, соскальзывающая или падающая с горного склона. Причина возникновения лавин — нарушение устойчивости снежного пласта, когда нагрузка на него превышает прочность его сцепления с нижележащим слоем или подстилающей поверхностью. Снежный покров в горах формируется слоями различной плотности и структуры, образуя так называемые «слабые слои» (глубинная изморозь, поверхностный иней, рыхлый снег), по которым и происходит отрыв лавины. Лавины представляют одну из главных объективных опасностей в горах: они способны перемещать огромные массы снега со скоростью до 200 км/ч. Человек, попавший в лавину, подвергается воздействию ударной волны, погребению под толщей снега и рискует погибнуть от асфиксии, травм или переохлаждения. По статистике, шанс выжить после погребения резко снижается после 15 минут — именно поэтому крайне важно иметь бипер, лопату и щуп, а также знать основы лавинной безопасности.'
WHERE title = '6.1. Что такое лавины';

UPDATE kg_nodes SET content = 'Лавины классифицируются по нескольким признакам. По типу снега: сухие (из свежевыпавшего или перемётного снега, движутся быстро, образуют снежное облако) и мокрые (из влажного снега, движутся медленнее, но обладают огромной разрушительной силой). По характеру отрыва: точечные (из одной точки, расширяясь вниз в форме капли) и пластовые (отрыв целого пласта по линии, наиболее опасные). По форме пути: лотковые (движутся по кулуарам и ложбинам), осовые (сползание широким фронтом) и прыгающие (летящие по воздуху после обрыва). Размер лавины оценивается по шкале от 1 до 5: от небольшого соскальзывания, способного сбить человека с ног, до катастрофической лавины, уничтожающей посёлки. Пластовые лавины наиболее опасны для альпинистов, так как отрыв часто провоцируется самим человеком, пересекающим склон.'
WHERE title = '6.2. Классификация лавин';

UPDATE kg_nodes SET content = 'Погодные условия оказывают решающее влияние на лавинную обстановку. Интенсивный снегопад (более 2 см/час) резко повышает лавинную опасность, так как новый снег не успевает стабилизироваться. Ветер переносит снег с наветренных склонов на подветренные, формируя опасные надувы (карнизы) и плотные ветровые доски. Резкое потепление или дождь ослабляют связь между слоями снега, провоцируя мокрые лавины. Солнечная радиация нагревает склоны южной экспозиции, вызывая подтаивание и снижение устойчивости снежного покрова. Период наибольшей лавинной опасности — во время снегопада и в течение 24-48 часов после него. Важно учитывать суточный цикл: утром снег стабильнее из-за ночного промерзания, а к полудню на солнечных склонах опасность возрастает.'
WHERE title = '6.3. Влияние погоды на лавины';

UPDATE kg_nodes SET content = 'Рельеф определяет, где именно формируются и сходят лавины. Наиболее опасны склоны крутизной 30-45 градусов — на них снег ещё держится, но легко срывается при дополнительной нагрузке. На склонах круче 50 градусов снег обычно не накапливается, а на склонах менее 25 градусов сходят только мокрые лавины. Вогнутые формы рельефа (кулуары, воронки) концентрируют снег и являются путями схода лавин. Выпуклые перегибы склона — типичные зоны отрыва пластовых лавин, так как здесь снежный пласт испытывает растягивающее напряжение. Экспозиция склона влияет на температурный режим снежного покрова: северные склоны дольше сохраняют нестабильный сухой снег, южные более подвержены мокрым лавинам. Растительность частично стабилизирует снег, но густой лес не является абсолютной гарантией безопасности.'
WHERE title = '6.4. Влияние рельефа на лавины';

UPDATE kg_nodes SET content = 'При передвижении по лавиноопасному рельефу необходимо соблюдать строгие правила безопасности. Каждый участник должен иметь лавинный датчик (бипер) во включённом состоянии на передачу, лопату и зонд. Пересекать потенциально лавинный склон следует по одному, с дистанцией 50-100 м между участниками. Наиболее безопасны гребни, контрфорсы и выступы скал; наиболее опасны — кулуары, мульды и подветренные склоны. Двигаться следует в утренние часы, когда снег ещё скреплён ночным морозом. Необходимо намечать безопасные зоны (скалы, деревья) и двигаться от укрытия к укрытию. Перед выходом на склон ослабьте лямки рюкзака, выньте руки из темляков палок, застегните одежду и закройте лицо. При движении по лавиноопасному участку сохраняйте тишину и избегайте рывковых движений.'
WHERE title = '6.5. Правила передвижения';

UPDATE kg_nodes SET content = 'Лавинные тесты позволяют оценить стабильность снежного покрова на конкретном склоне. Тест на сжатие (compression test): вырезается колонка снега 30x30 см и последовательно нагружается ударами руки — количество ударов до обрушения слоя показывает прочность слабого слоя. Тест лопатой (shovel shear test): изолированный столбик снега подрезается лопатой и оценивается усилие, необходимое для его смещения. Extended Column Test (ECT) — более информативный: вырезается блок 90x30 см и простукивается по одному краю, оценивается характер распространения разрушения по всей длине блока. «Красные флаги» лавинной опасности, не требующие тестов: свежие лавины поблизости, трещины «вумпф» под ногами (звук оседания снежного пласта), карнизы и надувы, быстрое потепление. При наличии хотя бы одного красного флага следует отказаться от движения по лавиноопасному склону.'
WHERE title = '6.6. Лавинные тесты';

UPDATE kg_nodes SET content = 'При попадании человека в лавину счёт идёт на минуты: вероятность выживания при полном погребении снижается до 50% уже после 15 минут. Алгоритм спасения: свидетели фиксируют точку, где пострадавшего видели в последний раз, переключают биперы в режим поиска и начинают поиск с нижней части лавинного выноса. Поиск бипером: грубый поиск (движение полосами шириной 20-40 м), точный поиск (сужение зоны до минимального показания), зондирование (щупом по спирали от точки минимума). При обнаружении — немедленное откапывание лопатой, начиная с нижней стороны (метод V-конвейера ускоряет процесс в 2-3 раза). После извлечения — проверка дыхания и сознания, при необходимости СЛР. Важно помнить, что 90% погибших в лавинах спасаются товарищами, а не профессиональными спасателями — скорость реакции группы решает всё.'
WHERE title = '6.7. Поиск в лавине';

-- ============================================================
-- Chapter 9: Снаряжение
-- ============================================================

UPDATE kg_nodes SET content = 'Правильная одежда в горах строится по принципу трёх слоёв. Базовый слой (термобельё) отводит влагу от тела и должен быть из синтетики или мериносовой шерсти — хлопок недопустим, так как намокает и не сохнет. Средний слой (утеплитель) сохраняет тепло: флис, пуховка или синтетический утеплитель. Внешний слой (мембранная куртка и брюки) защищает от ветра и осадков — мембрана Gore-Tex или аналоги. Обувь подбирается под тип маршрута: для скальных восхождений нужны жёсткие ботинки с рантом под полуавтоматические или автоматические кошки, для треккинга достаточно более лёгкой обуви. Ботинки должны быть разношены до восхождения. Обязательны гамаши для защиты от снега и влаги, перчатки нескольких видов (тонкие для работы с верёвкой и тёплые для холодных участков), а также запасные носки.'
WHERE title = '9.1. Одежда и обувь';

UPDATE kg_nodes SET content = 'Общее снаряжение включает всё необходимое для жизни в горах. Рюкзак должен соответствовать продолжительности выхода: 30-50 л для однодневного восхождения, 60-80 л для многодневного. Важна правильная регулировка подвесной системы — основная нагрузка должна приходиться на бёдра, а не на плечи. Палатка для альпинизма выбирается двухслойная, ветроустойчивая, с каркасом. Спальный мешок подбирается по температуре комфорта с запасом. Коврик (каремат) обеспечивает теплоизоляцию от земли — надувной теплее, но пенный надёжнее. Газовая горелка с ветрозащитным экраном и достаточный запас газа обязательны. Налобный фонарь с запасными батареями — критически важный элемент снаряжения, так как в горах часто приходится двигаться в темноте (ранние выходы, непредвиденные задержки). Солнцезащитные очки категории 3-4 и крем с SPF 50 необходимы на высоте.'
WHERE title = '9.2. Общее снаряжение';

UPDATE kg_nodes SET content = 'Специальное альпинистское снаряжение включает средства страховки и передвижения по сложному рельефу. Верёвка — основной элемент безопасности: динамическая (растяжение 30-40%) используется для страховки при лазании, статическая — для перил и спуска. Стандартная длина — 50-60 м, диаметр 9-10 мм. Страховочная система (беседка) должна быть сертифицирована CE/UIAA и подогнана по размеру — при зависании пояс не должен сдавливать диафрагму. Каска обязательна при любом движении по рельефу. Карабины бывают муфтованные (для станций и страховки) и немуфтованные (для оттяжек). Страховочные устройства: корзинка (ATC) — универсальное, Gri-Gri — с автоблокировкой для спортивного лазания, узел UIAA — аварийный вариант через карабин. Кошки подбираются под ботинки (полуавтомат или автомат), ледоруб — по росту (штычок на уровне щиколотки). Закладные элементы (закладки, гексы) и кулачковые устройства (френды) используются для организации точек страховки в трещинах скал. Корделет (репшнур 7 мм, 5-6 м) и петли (60-120 см) необходимы для организации станций и самостраховки.'
WHERE title = '9.3. Специальное снаряжение';

-- ============================================================
-- Chapter 11: Скальный рельеф
-- ============================================================

UPDATE kg_nodes SET content = 'Узлы — фундаментальный навык альпиниста, от правильности их вязки зависит жизнь. Узел «восьмёрка» — основной узел для привязывания к верёвке и организации станций, прост и надёжен, легко контролируется визуально. Узел «булинь» — используется для привязывания к опоре и организации станций, обязательно с контрольным узлом. Узел «стремя» (клов-хитч) — для самостраховки на станции, позволяет регулировать длину без перевязывания. Узел «UIAA» (полустремя, итальянский) — для страховки и спуска через карабин без специального устройства, универсальный аварийный приём. Схватывающие узлы: «прусик» (3 оборота) — для подстраховки при спуске и подъёма по верёвке, вяжется из репшнура 6-7 мм на основной верёвке 9-11 мм. Узел «проводник» — простая петля для создания точки на верёвке. «Грейпвайн» — для связывания концов верёвок одинакового диаметра, самый надёжный, но трудно развязывается после нагрузки. «Плоский» (простой) узел — для связывания верёвок при продёргивании спуска, легко проходит через перегибы рельефа, свободные концы не менее 30-40 см.'
WHERE title = '11.1. Рекомендованные узлы';

UPDATE kg_nodes SET content = 'Присоединение верёвки к беседке — первый и самый ответственный элемент страховочной цепи. Основной способ — ввязывание узлом «восьмёрка одним концом» (figure-eight follow-through) непосредственно в силовые петли беседки. Верёвка продевается через оба силовых кольца обвязки (поясное и ножные), узел затягивается, свободный конец должен быть не менее 15-20 см. Важно: верёвка должна проходить через те же точки, что и страховочная петля обвязки. Второй способ — привязывание двойным булинём, который также требует контрольного узла. Категорически запрещено пристёгиваться только через карабин к петле беседки при лидировании — карабин при падении может нагрузиться по боковой оси и разрушиться. После завязывания узла обязательна взаимная проверка партнёрами — это стандартная практика безопасности.'
WHERE title = '11.2. Присоединение верёвки к беседке';

UPDATE kg_nodes SET content = 'Самостраховка обеспечивает безопасность альпиниста на станции и при работе у края. Самостраховка организуется из отрезка динамической верёвки или специальной фабричной самостраховки и вщёлкивается в центральный карабин станции. Основной способ — из куска верёвки с узлом «восьмёрка» на одном конце (пристёгнут к беседке) и узлом «стремя» на другом (регулируемая длина на станции). Длина самостраховки должна быть такой, чтобы при зависании на ней альпинист не мог дотянуться до края обрыва. При подходе к станции первый пристёгивает самостраховку к центральному карабину и только после этого даёт команду «самостраховка» — с этого момента его напарник может прекращать страховку. Важно: нельзя использовать статическую петлю в качестве единственной самостраховки при вероятности рывка (фактор больше 0), так как жёсткий рывок может травмировать или разрушить элементы.'
WHERE title = '11.3. Самостраховка';

UPDATE kg_nodes SET content = 'Страховка — система удержания сорвавшегося альпиниста. Различают динамическую страховку (с протравливанием верёвки для смягчения рывка) и статическую (жёсткую). Динамическая страховка предпочтительна при нижней страховке, статическая — при верхней. Основные страховочные устройства: «корзинка» (ATC, Reverso) — универсальное устройство с двумя режимами, простое и надёжное; устройства с автоблокировкой (Gri-Gri) — зажимают верёвку при рывке, удобны для верхней страховки и работы с тяжёлыми грузами. Узел UIAA через муфтованный карабин — аварийный способ страховки без устройства. Принцип страховки: тормозная рука никогда не отпускает верёвку. При страховке лидера снизу верёвку выдают без слабины, но и не натягивают — лишняя слабина увеличивает глубину падения, а натяжение может сдёрнуть лидера. Страхующий должен стоять устойчиво, быть пристёгнут к станции и внимательно следить за лидером.'
WHERE title = '11.4. Страховка';

UPDATE kg_nodes SET content = 'Верхняя страховка (top-rope) организуется через верхнюю точку или станцию — верёвка идёт от страхующего вверх через точку и вниз к лезущему. Это наиболее безопасный способ: при срыве альпинист повисает на верёвке с минимальным падением. Используется при обучении и на подготовленных маршрутах. Нижняя страховка (лидирование) — лидер поднимается первым, прощёлкивая верёвку в промежуточные точки страховки. При срыве лидер падает на расстояние, равное удвоенному расстоянию до последней точки плюс растяжение верёвки. Страхующий при нижней страховке выдаёт верёвку по мере продвижения лидера и должен быстро выбирать слабину при необходимости. При прощёлкивании оттяжки верёвка не должна проходить Z-образно (через переднюю стенку нижнего карабина), иначе при срыве возможно раскрытие защёлки. Правильное направление верёвки: от обвязки лидера через заднюю сторону карабина оттяжки.'
WHERE title = '11.5. Верхняя и нижняя страховка';

UPDATE kg_nodes SET content = 'Оттяжки служат промежуточным звеном между верёвкой и точкой страховки. Стандартная оттяжка состоит из двух карабинов, соединённых петлёй (стропой). Верхний карабин вщёлкивается в точку страховки, нижний — для верёвки. При прощёлкивании верёвки важно, чтобы она шла от обвязки через заднюю часть нижнего карабина оттяжки — иначе при срыве верёвка может нагрузить защёлку карабина, что приведёт к его раскрытию. На длинных маршрутах используются оттяжки разной длины для уменьшения трения верёвки о рельеф (Z-образная нагрузка увеличивает трение и затрудняет выдачу/выбирание). Длинные оттяжки (петли 60-120 см) необходимы на траверсах и при обходе перегибов, чтобы не отклонять линию верёвки от прямой. На маршрут обычно берётся 10-14 оттяжек в зависимости от протяжённости.'
WHERE title = '11.6. Использование оттяжек';

UPDATE kg_nodes SET content = 'Спуск по верёвке (дюльфер) — основной способ спуска на сложном рельефе. При мультипитчевом спуске верёвку разделяют пополам, пропускают через спусковое кольцо станции, на концах завязывают узлы «полу-грейпвайн», сбрасывают вниз и спускаются по двойной верёвке на спусковом устройстве с подстраховкой схватывающим узлом. Первый участник спустившись организует новую станцию, встаёт на самостраховку, выдаёт себе верёвку через спусковое устройство оставив 2 м слабины для второго. Верёвка закрепляется на станции, второй спускается и оба участника продёргивают верёвку. Для продёргивания при связывании двух верёвок используется «плоский» узел (не «восьмёрка»!), свободные концы не менее 30-40 см. При спуске по необорудованному маршруту всегда усиливайте старые стационарные петли — ультрафиолет, вода и мороз снижают их прочность на 30-50% и более за год. Важно: при спуске нельзя допускать трение верёвки о ветви станции и самостраховки.'
WHERE title = '11.7. Организация спуска';

UPDATE kg_nodes SET content = 'Движение связки по многоверёвочному маршруту строится по принципу попеременной страховки: лидер поднимается, организуя промежуточные точки, строит станцию наверху и принимает второго. На простом рельефе используется одновременное движение — оба участника двигаются одновременно, лидер оставляет точки страховки (петли на выступах, закладки), второй их снимает. Веревку укорачивают до 15-20 м, она всегда под натяжением. При попеременном движении используется естественный рельеф — выступы, жандармы, «песочные часы» — это быстрее и надёжнее закладных элементов. Для спрямления верёвки используются более длинные оттяжки-петли. Оценивайте хорошие места для станции: иногда лучше пройти 20-30 м дополнительно и принять партнёра в удобном месте, чем строить станцию в неудобном. При движении по гребню участники связки могут находиться на разных сторонах гребня, используя перегиб как точку страховки.'
WHERE title = '11.8. Движение связки по маршруту';

UPDATE kg_nodes SET content = 'Подъём по закреплённой верёвке (перилам) осуществляется несколькими способами. На скалах рекомендуется использование зажимов (жумаров): зажим прищёлкивается к верёвке так, чтобы при зависании рука доставала до ручки, с педалью для ноги. При движении по перилам нельзя допускать расположения зажима ниже пояса из-за увеличения фактора рывка. Подъём на схватывающих узлах (двух корделетах) — аварийный вариант: два узла «прусик» в 3 оборота, верхний ввязывается в страховочную систему узлом «проводник», нижний крепится к педали для ноги. Расстояние от нижнего схватывающего до верхнего — 10-15 см. Важно правильно выбрать длину петли: под нагрузкой должно быть легко дотягиваться до схватывающего узла. Подъём при помощи спускового устройства и одного корделета: устройство в режиме автоблокировки, схватывающий узел с педалью — подъём происходит за счёт шага на педаль и выбирания верёвки через устройство.'
WHERE title = '11.9. Спуск по закреплённой верёвке';

UPDATE kg_nodes SET content = 'Промежуточные точки страховки обеспечивают удержание лидера при срыве. Их надёжность зависит от типа элемента, качества скалы и опыта установки. Крючья забиваются в подходящие трещины акцентированными ударами молотка до повышающегося тонкого звона — глухой звук означает непригодность крюка для данной трещины. Крюк должен работать при нагрузке на заглубление. Закладки (стопперы) легко устанавливаются и извлекаются, не портят скалу, работают в сужающихся щелях. После установки необходимо резким рывком усадить закладку в щель. Закладки работают только в одном направлении, поэтому при необходимости ставится оппозитная точка. Френды (кулачковые устройства) удобны, надёжны, работают в параллельных щелях и в разных направлениях. Не ставьте френд до упора — должен оставаться свободный ход кулачков для извлечения. Френд располагается по линии предполагаемой нагрузки. Все закладные элементы плохо работают на обледеневшем, мокром и грязном рельефе.'
WHERE title = '11.10. Точки страховки';

UPDATE kg_nodes SET content = 'Страховочная станция — система сблокированных точек страховки для организации страховки на многоверёвочном маршруте. Станция состоит из двух и более точек, соединённых между собой, и должна выдерживать нагрузку от 20 kN. Станции делятся на фиксированные и компенсационные. Фиксированные станции работают в одном направлении нагрузки: из петли (выбрать направление и завязать узел «проводник»), из корделета (несколько вариантов блокировки точек). Плюс: при вылете одной точки нет шокового рывка. Минус: при изменении направления нагрузка распределяется неравномерно. Компенсационные станции распределяют нагрузку равномерно на все точки и могут менять направление. Минус: при вырывании одной точки происходит шоковый рывок. Важно учитывать: чем больше угол между ветвями станции, тем больше нагрузка на точки (при 120 градусах каждая точка нагружается на 100% от приложенной силы!). Оптимальный угол — менее 60 градусов. Типичная ошибка — «американский мёртвый треугольник», стягивающий точки друг к другу.'
WHERE title = '11.11. Страховочные станции';

UPDATE kg_nodes SET content = 'Фактор рывка — отношение глубины падения к длине выданной верёвки. Это ключевой показатель, определяющий силу рывка при срыве. Максимальный фактор рывка — 2 (падение вдвое превышает длину верёвки, например, срыв лидера при нижней страховке без промежуточных точек). Современные динамические верёвки при факторе 2 обеспечивают силу рывка в пределах 12 kN. Максимально допустимая нагрузка на тело человека — 12 kN, нагрузки выше способны серьёзно травмировать. На верхнюю точку страховки приходится нагрузка C = 1,66 * A (где A — сила рывка), так как верёвка проходит через карабин с потерей 1/3 силы на трение. Точки страховки уменьшают глубину падения, поэтому первая (направляющая) точка — самая важная. Рекомендуется: первую точку ставить в 1 м выше станции, вторую — не выше 2 м, третью — в 4 м, далее увеличивая интервал. Перегибы и трение о рельеф ухудшают динамические свойства верёвки — на перегибе в 45 градусов теряется почти половина энергии. Для полноценной работы верёвки нужны длинные оттяжки.'
WHERE title = '11.12. Фактор рывка';

UPDATE kg_nodes SET content = 'Одновременное движение связки применяется на простом рельефе (гребни, несложные склоны), где возможность падения невысока. Лидер оставляет точки страховки (петли на выступах, закладки), второй их снимает. Верёвку укорачивают до 15-20 м маркировкой на себя или убиранием в рюкзак. Она всегда должна быть под натяжением — при появлении слабины второй ждёт первого. На снежных гребнях можно использовать бо'||chr(769)||'льшую длину верёвки, так как на снегу падение не столь стремительно и длина верёвки даёт запас времени на самозадержание. Попеременное движение применяется на более сложном рельефе: страховка лидера организуется вторым участником со станции. При попеременном движении используйте естественный рельеф — выступы, жандармы, «песочные часы» — это проще, надёжнее и быстрее, чем закладные элементы. При работе на несложных маршрутах удобно использовать узел UIAA как для верхней, так и для нижней страховки.'
WHERE title = '11.13. Движение по гребню';

UPDATE kg_nodes SET content = 'Техника лазания по скалам основана на работе ног и балансе тела. Основные принципы: всегда должны работать три точки опоры; нагрузка распределяется преимущественно на ноги, руки используются для баланса. Перед лазанием необходимо провести разминку (пальцы, поясница, шейный отдел, руки и ноги) и мысленно «прочитать» маршрут, определив ключевые движения и места отдыха. Виды хватов: закрытый (активный) — самый сильный, но травмоопасный; открытый — менее силовой, но безопаснее; щипок — ладонью и большим пальцем; подхват — перевёрнутые зацепки снизу. Техника «распор» и каминное лазание — альпинист распирается между стенками. Лазание «в откидку» — использование щелей с откидыванием корпуса и контрупором ног. В горах всегда проверяйте зацепки лёгким ударом руки: гулкий звук означает неустойчивую породу. Зацепки нагружать вниз, а не на себя. Научитесь находить места отдыха, стоя на ногах для разгрузки рук.'
WHERE title = '11.15. Техника лазания';

UPDATE kg_nodes SET content = 'Переноска снаряжения по скальному маршруту требует продуманной организации. Верёвку без рюкзака переносят, собрав на руке или на шее: два конца оставить несмаркированными (3-4 м), обернуть бухту и зафиксировать, концы обвить вокруг себя как лямки. Петли переносятся укороченными через плечо, длинные оттяжки укорачиваются (продеваются через себя). Снаряжение развешивается на обвязке в определённом порядке для быстрого доступа: оттяжки — на передних петлях снаряжения, закладные элементы и френды — сбоку, карабины и петли — сзади. Минимальный набор для скального маршрута: каска, беседка, самостраховка, спусковое устройство, 2 корделета, репшнур, 4 карабина, 4 петли (60-120 см), 10-14 оттяжек, набор френдов (7-10 шт.), набор закладок (7-10 шт.), крючья и молоток (по маршруту), 1-2 верёвки, экстрактор (один на связку), налобный фонарь.'
WHERE title = '11.16. Переноска снаряжения';

UPDATE kg_nodes SET content = 'Подъём и спуск на схватывающих узлах с использованием двух корделетов — аварийный вариант подъёма по верёвке (например, после падения в трещину) или при разрушении верхней точки. Для организации системы: два узла «прусик» в 3 оборота, верхний ввязывается в страховочную систему, нижний крепится к педали для ноги. Расстояние между узлами — 10-15 см. Длину петли подобрать так, чтобы под нагрузкой легко дотягиваться до схватывающего узла, а в ненагруженном состоянии узел был на уровне поднятой руки. Чтобы узлы легче сдвигались после нагрузки, их надо немного поворачивать для расслабления. Переход с подъёма на спуск: завязать ниже страховочного устройства узел «стремя» и вщёлкнуть в силовое кольцо как подстраховку, максимально поднять схватывающий узел, нагрузить и ослабить устройство, перевести его в режим спуска, встать на педаль, освободить схватывающий узел, освободить верёвку ниже устройства и начать спуск с подстраховкой схватывающим узлом.'
WHERE title = '11.17. Проблемы и решения';

-- ============================================================
